mapper.select:
		/* oms-master-orType-sql-oracle.xml selectOrTypeCount */
        SELECT COUNT(1)
          FROM TORDER_MST_ORTYPE A


			 	   #{SEARCH_CONDITION}

/* oms-master-orType-sql-oracle.xml selectOrTypeList */ #{GRIDPAGING_ROWNUMTYPE_TOP} SELECT '0' AS CHK , A.OWKEY , O.OWNM AS OWKEYNM , A.ORDERTYPECD AS SERVERORDERTYPECD , A.ORDERTYPECD , A.ORDERTYPENM , COALESCE(A.IBYN, 'N') AS IBYN , COALESCE(A.OBYN, 'N') AS OBYN , A.ORDERAT , A.WMSIBTYPE , A.WMSOBTYPE , A.TMSOBTYPE , COALESCE(A.SOYN, 'N') AS SOYN , COALESCE(A.STOCKYN, 'N') AS STOCKYN , COALESCE(A.WMSORDERCREATEYN, 'N') AS WMSORDERCREATEYN , COALESCE(A.TMSORDERCREATEYN, 'N') AS TMSORDERCREATEYN , COALESCE(A.WMSYN, 'N') AS WMSYN , COALESCE(A.TMSPERFMANSYN, 'N') AS TMSPERFMANSYN , COALESCE(A.WMSPERFMANSYN, 'N') AS WMSPERFMANSYN , A.PERFMANSTYPE , COALESCE(A.ORDERSEPYN, 'N') AS ORDERSEPYN , COALESCE(A.ICCOMBINATYN, 'N') AS ICCOMBINATYN , 'Y' AS IS_OWSPCVERIFICATION , COALESCE(A.OPENORDERYN, 'N') AS OPENORDERYN , COALESCE(STATYN, 'N') AS STATYN , COALESCE(POCALINCYN, 'N') AS POCALINCYN , COALESCE(A.DELYN, 'N') AS DELYN , COALESCE(A.EOSENDTYPE, 'AUTO') AS EOSENDTYPE , A.INSERTDATE , A.INSERTURKEY , A.UPDATEDATE , A.UPDATEURKEY --, COALESCE(A.UNSETYN, 'N') AS UNSETYN --, COALESCE(A.ICUT_CHK_BY_CT_YN, 'N') AS ICUT_CHK_BY_CT_YN --, COALESCE(A.DLDAYYN, 'N') AS DLDAYYN --, A.OWSPCVERIFICATION FROM TORDER_MST_ORTYPE A LEFT JOIN TORDER_MST_OW O ON A.OWKEY = O.OWKEY WHERE 1 = 1
AND #{SEARCH_CONDITION}
AND A.OWKEY = #{owkey}
AND A.ORDERTYPECD = #{orTypeCd}
ORDER BY #{colName} DESC
ORDER BY #{colName} ASC
ORDER BY LPAD(A.ORDERTYPECD::TEXT, 20, '0')
#{GRIDPAGING_ROWNUMTYPE_BOTTOM}

/* oms-master-orType-sql-oracle.xml selectOwspcCodes */
SELECT OWCDDTKEY AS FIELD1
	 , OWCDDTKEY||':'||OWCDDTNM AS FIELD2
	 , '1' AS CHK			 
FROM TADMIN_MST_OWCD_DT
WHERE OWKEY = #{owkey}
  AND OWCDHDKEY = 'OMSCODE98'
  AND LAKEY = #{lakey}
  AND DELYN = 'N'
ORDER BY OWCDDTORDER

		SELECT COUNT(1)
		  FROM TORDER_MST_ORTYPE	
    	 WHERE OWKEY = #{owkey}
    	   AND ORDERTYPECD = #{ordertypecd}

	/* oms-master-orType-sql-oracle.xml checkOrTypeDt */
		SELECT COUNT(1)
		  FROM TORDER_INFO_CO_CHK	
    	 WHERE OWKEY = #{owkey}
    	   AND ORDERTYPECD = #{ordertypecd}	
    	   AND HDDTDIV = #{hddtdiv}
    	   AND COCOLUMN = #{cocolumn}

mapper.insert:
/* oms-master-orType-sql-oracle.xml insertOrType */
	INSERT INTO TORDER_MST_ORTYPE
	(
	      OWKEY
	    , ORDERTYPECD
	    , ORDERTYPENM
	    , IBYN
	    , OBYN
		, ORDERAT
	    , SOYN
	    , WMSORDERCREATEYN
	    , TMSORDERCREATEYN
	    , WMSIBTYPE
	    , WMSOBTYPE
	    , TMSOBTYPE
	    , WMSPERFMANSYN
		, TMSPERFMANSYN
		, OPENORDERYN
		, PERFMANSTYPE
		, POCALINCYN
	    , STATYN
	    , DELYN
	    , EOSENDTYPE
	    , INSERTDATE
	    , INSERTURKEY
	    , UPDATEDATE
	    , UPDATEURKEY

	)
	VALUES
	(
	      #{owkey}
	    , #{ordertypecd}
	    , #{ordertypenm}
	    , #{ibyn}
	    , #{obyn}
		, #{orderat}
	    , #{soyn}
	    , #{wmsordercreateyn}
	    , #{tmsordercreateyn}
	    , #{wmsibtype}
	    , #{wmsobtype}
	    , #{tmsobtype}
	    , #{wmsperfmansyn}
		, #{tmsperfmansyn}
		, #{openorderyn}
		, #{perfmanstype}
	    , #{pocalincyn}
	    , #{statyn}
	    , #{delyn}
	    , #{eosendtype}
	    , #{sysdate}
	    , #{surkey}
	    , #{sysdate}
	    , #{surkey}
	)

/* oms-master-orType-sql-oracle.xml insertOrTypeDt */
	INSERT INTO TORDER_INFO_CO_CHK
	(
	      OWKEY
	    , ORDERTYPECD -- OR_TYPE_CD
	    , HDDTDIV -- HDGB
	    , COCOLUMN
	    , REQRDYN -- ISMANDATORY
	    , DEFVAL -- DEFAULT_VALUE
	    , CDRFRNCTYPE -- CODE_REF_TYPE
	    , CDRFRNCVAL -- CODE_REF_VALUE
	    , DELYN
	    , INSERTDATE
	    , INSERTURKEY
	    , UPDATEDATE
	    , UPDATEURKEY
	)
	VALUES 
	(
	      #{owkey}
	    , #{ordertypecd}
	    , #{hddtdiv}
	    , #{cocolumn}
	    , #{reqrdyn}
	    , #{defval}
	    , #{cdrfrnctype}
	    , #{cdrfrncval}
	    , #{delyn}
	    , #{sysdate}
	    , #{surkey}
	    , #{sysdate}
	    , #{surkey}
	)

mapper.update:
/* oms-master-orType-sql-oracle.xml updateOrType */
	UPDATE TORDER_MST_ORTYPE
	   SET ORDERTYPENM      = #{ordertypenm} -- OR_TYPE_NAME
	     , IBYN             = #{ibyn}      
	     , OBYN             = #{obyn}
	     , ORDERAT          = #{orderat} -- ORDER_ATTR
	     , SOYN             = #{soyn}
	     , WMSORDERCREATEYN = #{wmsordercreateyn}
	     , TMSORDERCREATEYN = #{tmsordercreateyn}
	     , WMSIBTYPE        = #{wmsibtype} -- IBHDTYPE    
	     , WMSOBTYPE        = #{wmsobtype} -- OBHDTYPE
	     , TMSOBTYPE        = #{tmsobtype} -- TMSOBHDTYPE
	     , WMSPERFMANSYN    = #{wmsperfmansyn} -- WMSPERFORMANCEYN
		 , TMSPERFMANSYN    = #{tmsperfmansyn} -- TMSPERFORMANCEYN
		 , OPENORDERYN      = #{openorderyn}
		 , PERFMANSTYPE     = #{perfmanstype} -- PERFORMANCETYPE
		 , POCALINCYN  = #{pocalincyn}
		 , STATYN  = #{statyn}
		 , EOSENDTYPE  = #{eosendtype}
	     , DELYN            = #{delyn}
	     , UPDATEDATE       = #{sysdate}
	     , UPDATEURKEY      = #{surkey}
	 WHERE OWKEY = #{owkey}
	   AND ORDERTYPECD = #{ordertypecd}

/* oms-master-orType-sql-oracle.xml updateOrTypeDt */
	UPDATE TORDER_INFO_CO_CHK
	   SET REQRDYN     = #{reqrdyn} -- ISMANDATORY
	     , DEFVAL      = #{defval} -- DEFAULT_VALUE
	     , CDRFRNCTYPE = #{cdrfrnctype} -- CODE_REF_TYPE
	     , CDRFRNCVAL  = #{cdrfrncval} -- CODE_REF_VALUE
	     , DELYN       = #{delyn}
	     , UPDATEDATE  = #{sysdate}
	     , UPDATEURKEY = #{surkey}
	 WHERE OWKEY = #{owkey}
	   AND ORDERTYPECD = #{ordertypecd}
	   AND HDDTDIV = #{hddtdiv}
	   AND COCOLUMN = #{cocolumn}
